### [208.Implement Trie (Prefix Tree)](https://leetcode.com/problems/implement-trie-prefix-tree/)

> 20170209

基本字典树

```cpp
class Trie {
public:
    struct Node
    {
        Node *nex[26];
        bool word;
        Node(){memset(nex, NULL, sizeof(nex)), word = false;}
    };
    Node *root;
    /** Initialize your data structure here. */
    Trie() {
        root = new Node;
    }

    /** Inserts a word into the trie. */
    void insert(string word) {
        Node *p = root;
        for(auto c : word)
        {
            if(p->nex[c - 'a'] == NULL)
                p->nex[c - 'a'] = new Node;
            p = p->nex[c - 'a'];
        }
        p->word = true;
    }

    /** Returns if the word is in the trie. */
    bool search(string word) {
        Node *p = root;
        for(auto c : word)
        {
            if(p->nex[c - 'a'] == NULL)
                return false;
            p = p->nex[c - 'a'];
        }
        return p->word;
    }

    /** Returns if there is any word in the trie that starts with the given prefix. */
    bool startsWith(string prefix) {
        Node *p = root;
        for(auto c : prefix)
        {
            if(p->nex[c - 'a'] == NULL)
                return false;
            p = p->nex[c - 'a'];
        }
        return true;
    }
};

/**
 * Your Trie object will be instantiated and called as such:
 * Trie obj = new Trie();
 * obj.insert(word);
 * bool param_2 = obj.search(word);
 * bool param_3 = obj.startsWith(prefix);
 */
```

### [207.Course Schedule](https://leetcode.com/problems/course-schedule/)

> 20170208

先构造个图。一开始没想拓扑排序的事，就用DFS来判断的，标记-1表示`尚未考察`，0表示`暂没结果`，1表示`确认可选修`。
```CPP
class Solution {
public:
    vector<int> fst, nex, v;
    vector<int> ok;
    bool DFS(int i)
    {
        if(ok[i] != -1) return ok[i];
        ok[i] = 0;
        for(int j = fst[i]; j != -1; j = nex[j])
            if(!DFS(v[j]))
                return ok[i] = 0;
        return ok[i] = 1;
    }
    bool canFinish(int numCourses, vector<pair<int, int>>& prerequisites) {
        fst.resize(numCourses + 1, -1);
        ok.resize(numCourses + 1, -1);
        for(int i = 0; i < prerequisites.size(); i ++)
        {
            nex.push_back(fst[prerequisites[i].first]);
            fst[prerequisites[i].first] = nex.size() - 1;
            v.push_back(prerequisites[i].second);
        }
        for(int i = numCourses - 1; i >= 0; i --)
            numCourses -= DFS(i);
        return !numCourses;
    }
};
```

