> 20170208

好像又是老题

```cpp
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode(int x) : val(x), next(NULL) {}
 * };
 */
class Solution {
public:
    ListNode* reverseList(ListNode* head) {
        ListNode *pre = NULL;
        while(head != NULL)
        {
            ListNode *tmp = head->next;
            head->next = pre;
            pre = head;
            head = tmp;
        }
        return pre;
    }
};
```

### [205.Isomorphic Strings](https://leetcode.com/problems/isomorphic-strings/)

> 20170208

思路一是两个map互相映射，出现矛盾则说明不同构。两个map用于解决其中一个串可能有多个字符对应另一个串同一个字符，只用一个map则会掉这个坑。、

```cpp
class Solution {
public:
    bool isIsomorphic(string s, string t) {
        vector<char> mp1(128, 0), mp2(128, 0);
        for(int i = 0; i < s.length(); i ++)
        {
            if(!mp1[s[i]]) mp1[s[i]] = t[i];
            if(!mp2[t[i]]) mp2[t[i]] = s[i];
            if(mp1[s[i]] != t[i] || mp2[t[i]] != s[i])
                return false;
        }
        return true;
    }
};
```
思路二是把俩字符串按同一规则转换，转换后字符串直接比较。

```cpp
class Solution {
public:
    void convert(string &s)
    {
        vector<char> mp(128, 0);
        int p = 1;
        for(int i = 0; i < s.length(); i ++)
        {
            if(!mp[s[i]]) mp[s[i]] = p ++;
            s[i] = mp[s[i]];
        }
    }
    bool isIsomorphic(string s, string t) {
        convert(s);
        convert(t);
        return s == t;
    }
};
```
### [204.Count Primes](https://leetcode.com/problems/count-primes/)

> 20170208

筛素数，以前比赛时候写的滚瓜烂熟的，现在竟然忘了还复习一下……
从2开始把每个其倍数都标记成合数，然后往后枚举，枚举到的没标记的一定是素数（如果它是合数，它的质因数肯定比它小，而比它小的质数的倍数都已经标记过了），继续标记其所有倍数。

```cpp
class Solution {
public:
    int countPrimes(int n) {
        int ret = 0;
        vector<bool> pr(n, true);
        for(int i = 2; i < n; i ++)
        {
            if(pr[i])
            {
                ret ++;
                for(int j = i << 1; j < n; j += i)
                    pr[j] = false;
            }
        }
        return ret;
    }
};
```
### [203.Remove Linked List Elements](https://leetcode.com/problems/remove-linked-list-elements/)

> 20170208

好像又是老题，开头加个哨兵节点就不用担心head节点被删除的情况了。

```cpp
/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode(int x) : val(x), next(NULL) {}
 * };
 */
class Solution {
public:
    ListNode* removeElements(ListNode* head, int val) {
        ListNode *pre = new ListNode(0);
        pre->next = head;
        for(ListNode *p = pre; head != NULL; head = head->next)
        {
            if(head->val == val)
            {
                p->next = head->next;
            }
            else
                p = head;
        }
        return pre->next;
    }
};
```
### [202.Happy Number](https://leetcode.com/problems/happy-number/)

> 20170208

直接思路是用哈希记录判循环，降低空间复杂度可以用两个值一个每次算一步，另一个每次算两步来判循环。
还有个方法是只要大于 6 就一直进行，能保证计算结束，不知道怎么证明的。
代码放传统思路。

```cpp
class Solution {
public:
    int SumSquare(int x)
    {
        int ret = 0;
        while(x)
        {
            ret += (x % 10) * (x % 10);
            x /= 10;
        }
        return ret;
    }
    bool isHappy(int n) {
        unordered_set<int> s;
        while(!s.count(n))
        {
            s.insert(n);
            n = SumSquare(n);
        }
        return s.count(1);
    }
};
```
### [201.Bitwise AND of Numbers Range](https://leetcode.com/problems/bitwise-and-of-numbers-range/)\*

> 20170208

二进制从左往右看，当遇到某位不相等的时候，最终结果后面的位都会是0，因为在`n~m`之间，连续的数字中这些位肯定会出现0。题目巧在如果思路转换为求二进制最长相同前缀，代码就很简单了。

```cpp
class Solution {
public:
    int rangeBitwiseAnd(int m, int n) {
        int cnt = 0;
        while(m != n)
        {
            m >>= 1;
            n >>= 1;
            cnt ++;
        }
        return m << cnt;
    }
};
```
还有一种理解方式也很好，把n的右侧的1一一去掉，当n不大于m的时候，n剩下的就是那个相同前缀。

```cpp
class Solution {
public:
    int rangeBitwiseAnd(int m, int n) {
        while(n > m)
            n = n & (n - 1);
        return n;
    }
};
```
### [200.Number of Islands](https://leetcode.com/problems/number-of-islands/)

> 20170208

我一定是做了道假题。。DFS、BFS随便做，好陈旧。

```cpp
class Solution {
public:
    const int dx[4] = {1, -1, 0, 0};
    const int dy[4] = {0, 0, 1, -1};
    int row, col;
    void BFS(vector<vector<char>> &grid, int x, int y)
    {
        queue<pair<int, int> > q;
        q.push(make_pair(x, y));
        grid[x][y] = 0;
        while(!q.empty())
        {
            pair<int, int> now = q.front();
            q.pop();
            for(int i = 0; i < 4; i ++)
            {
                pair<int, int> nex = make_pair(now.first + dx[i], now.second + dy[i]);
                if(nex.first >= 0 && nex.first < row && nex.second >= 0 && nex.second < col && grid[nex.first][nex.second] == '1') 
                {
                    grid[nex.first][nex.second] = 0;
                    q.push(nex);
                }
            }
        }
    }
    int numIslands(vector<vector<char>>& grid) {
        int ret = 0;
        if(grid.size() == 0) return 0;
        row = grid.size();
        col = grid[0].size();
        for(int i = 0; i < grid.size(); i ++)
        {
            for(int j = 0; j < grid[0].size(); j ++)
            {
                if(grid[i][j] == '1')
                    ret ++, BFS(grid, i, j);
            }
        }
        return ret;
    }
};
```
