 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:
    struct Node
    {
        TreeNode *p;
        int layer;
        Node(TreeNode *p_, int layer_):p(p_), layer(layer_){}
    };
    vector<int> rightSideView(TreeNode* root) {
        queue<Node> q;
        vector<int> ret;
        if(root != NULL)
            q.push(Node(root, 0));
        int last = -1;
        while(!q.empty())
        {
            Node now = q.front();
            q.pop();
            if(last != now.layer)
            {
                last = now.layer;
                ret.push_back(now.p->val);
            }
            if(now.p->right != NULL)
                q.push(Node(now.p->right, now.layer + 1));
            if(now.p->left != NULL)
                q.push(Node(now.p->left, now.layer + 1));
        }
        return ret;
    }
};
```
### [198.House Robber](https://leetcode.com/problems/house-robber/)

> 20170207

简单的动态规划，两个数一个表示`上一个没rob`的当前最佳收益，另一个表示`上一个rob了`的，反复更新。

```cpp
class Solution {
public:
    int rob(vector<int>& nums) {
        int dp[2] = {0};
        for(auto m : nums)
        {
            int tmp = dp[1];
            dp[1] = max(dp[1], dp[0] + m);
            dp[0] = max(dp[0], tmp);
        }
        return max(dp[1], dp[0]);
    }
};
```
### [191.Number of 1 Bits](https://leetcode.com/problems/number-of-1-bits/)

> 20170207

做过树状数组应该对`n&(n-1)`很熟了，`n-1`让二进制末尾的1变0，这个1后面的0都变1，和`n`做按位与就相当于去掉了最后一个1，这样每次操作都能去掉一个1，一位一位统计就快多了。

```cpp
class Solution {
public:
    int hammingWeight(uint32_t n) {
        int cnt = 0;
        while(n)
        {
