对每个长度为10的串进行统计，大于1次就做记录。

```cpp
class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        unordered_map<string, bool> mp;
        vector<string> ret;
        for(int i = 10; i <= s.length(); i ++)
        {
            string tmp = s.substr(i - 10, 10);
            if(!mp.count(tmp))
                mp[tmp] = 0;
            else if(mp[tmp] == 0)
            {
