### [152.Maximum Product Subarray](https://leetcode.com/problems/maximum-product-subarray/)
维护当前位置连续乘积的最大值 tmpp 和最小值 tmpn ，最大值和最小值都可能由三种情况得到：上一个数的 tmpp<em>A[i]，上一个数的 tmpn</em>A[i]，A[i]本身。

不断更新答案，最终输出。

```cpp
 class Solution {
 public:
     int maxProduct(int A[], int n) {
         int tmpp = A[0], tmpn = A[0], tmp, ans = A[0];
         for(int i = 1; i < n; i ++)
         {
             tmp = tmpp;
             tmpp = max(max(A[i], A[i] * tmpp), A[i] * tmpn);
             tmpn = min(min(A[i], A[i] * tmp), A[i] * tmpn);
             ans = max(ans, tmpp);
         }
         return ans;
     }
 };
```
### [151.Reverse Words in a String](http://oj.leetcode.com/problems/reverse-words-in-a-string/)
先翻转整个字符串，然后从前往后一个单词一个单词地再翻转一次，同时去除多余空格，等于是扫描两遍，O(n)。

```cpp
 class Solution {
 public:
     void reverseWords(string &s) {
         reverse(s.begin(), s.end());
         int start = 0, end = 0, j = 0;
         while(start != s.length())
         {
             while(start != s.length() && s[start] == ' ') start ++;
             for(end = start; end != s.length() && s[end] != ' '; end ++);
             if(j != 0 && start <= end - 1) s[j ++] = ' ';
             for(int i = end - 1; start < i; start ++, i --)
                 swap(s[i], s[start]), s[j ++] = s[start];
             while(start < end) s[j ++] = s[start ++];
         }
         s.resize(j);
     }
 };
```
### [150.Evaluate Reverse Polish Notation](http://oj.leetcode.com/problems/evaluate-reverse-polish-notation/)
逆波兰表达式计算四则运算。用栈。

```cpp
 class Solution {
 public:
     int evalRPN(vector &tokens) {
         int a, b;
         stack s;
         for(int i = 0; i < tokens.size(); i ++) { if(isdigit(tokens[i][0]) || tokens[i].length() > 1)
             {
                 s.push(atoi(tokens[i].c_str()));
                 continue;
             }
             a = s.top();s.pop();
             b = s.top();s.pop();
             switch(tokens[i][0])
             {
                 case '+': s.push(b + a); break;
                 case '-': s.push(b - a); break;
                 case '*': s.push(b * a); break;
                 case '/': s.push(b / a); break;
             }
         }
         return s.top();
     }
 };
```
### [149.Max Points on a Line](http://oj.leetcode.com/problems/max-points-on-a-line/)
平面上一条直线最多穿过多少点。乍一看好熟悉的问题，做了这么久计算几何。。。却还真没做过这个小问题。

第一反应当然不能O(n^3)枚举了，枚举圆周好像也不行，毕竟是考察所有点，不是某个点。那么应该就是哈希斜率了吧。

肯定少不了竖直的线，哈希斜率这不像是这类OJ让写的题吧。。忘了map这回事了。

确定思路之后，还是看看别人博客吧，少走点弯路，然后就学习了还有unordered_map这么个东西，[还有一个博客](http://blog.csdn.net/tontkeng/article/details/17244361) 的思路挺好，避免double问题，把斜率转化成化简的x、y组成字符串。

再另外就是重叠的点了，想让题目坑一点，怎能少得了这种数据，单独处理一下。

```cpp
 /**
  * Definition for a point.
  * struct Point {
  *     int x;
  *     int y;
  *     Point() : x(0), y(0) {}
  *     Point(int a, int b) : x(a), y(b) {}
  * };
  */
 class Solution {
 public:
     int maxPoints(vector &points) {
         int ans = 0;
         for(int i = 0; i < points.size(); i ++)
         {
             unordered_map<string, int> mp;
             int tmpans = 0, same = 0;
             for(int j = i + 1; j < points.size(); j ++)
             {
                 int x = points[j].x - points[i].x, y = points[j].y - points[i].y;
                 int g = gcd(x, y);
                 if(g != 0) x /= g, y /= g;
                 else {same ++; continue;}
                 if(x < 0) x = -x, y = -y;
                 string tmp = to_string(x) + " " + to_string(y);
                 if(!mp.count(tmp)) mp[tmp] = 1;
                 else mp[tmp] ++;
                 tmpans = max(tmpans, mp[tmp]);
             }
             ans = max(tmpans + 1 + same, ans);
         }
         return ans;
     }
     int gcd(int a, int b)
     {
         return a ? gcd(b % a, a) : b;
     }
 };
```
### [148.Sort List](http://oj.leetcode.com/problems/sort-list/)
又长见识了，原来链表也可以O(nlogn)排序的。没往下想就查了一下，看到人说用归并，于是才开始想能不能实现。。。

O(n)找到中点，把中点的next变成NULL，对两部分递归。递归结束后对两部分归并，先找到newhead，即两部分的头部val较小的那个，然后归并就把小的从newhead往后续。

把最后的next赋值NULL，返回newhead。

又有空数据@_@.

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *sortList(ListNode *head) {
         int n = 0;
         ListNode *p = head;
         while(p != NULL)
             n ++, p = p->next;
         if(n <= 1) return head; n >>= 1;
         p = head;
         while(-- n)
             p = p->next;
         ListNode *tmp = p->next;
         p->next = NULL;
         ListNode *nl = sortList(head);
         ListNode *nr = sortList(tmp);
         ListNode *newhead;
         if(nl->val < nr->val)
         {
             newhead = nl;
             nl = nl->next;
         }
         else
         {
             newhead = nr;
             nr = nr->next;
         }
         p = newhead;
         while(nl != NULL && nr != NULL)
         {
             if(nl->val < nr->val) p->next = nl, p = p->next, nl = nl->next;
             else p->next = nr, p = p->next, nr = nr->next;
         }
         while(nl != NULL) p->next = nl, p = p->next, nl = nl->next;
         while(nr != NULL) p->next = nr, p = p->next, nr = nr->next;
         p->next = NULL;
         return newhead;
     }
 };
```
### [147.Insertion Sort List](http://oj.leetcode.com/problems/insertion-sort-list/)
指针操作很烦啊。。暴力枚举插入位置，注意细节就能过了。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *insertionSortList(ListNode *head) {
         ListNode *newhead = head;
         if(head == NULL) return NULL;
         head = head->next;
         newhead->next = NULL;
         while(head != NULL)
         {
             if(head->val < newhead->val)
             {
                 ListNode *tmp = head->next;
                 head->next = newhead;
                 newhead = head;
                 head = tmp;
                 continue;
             }
             ListNode *pre = newhead, *p = newhead->next;
             while(p != NULL && p->val < head->val)
             {
                 p = p->next;
                 pre = pre->next;
             }
             pre->next = head;
             head = head->next;
             pre = pre->next;
             pre->next = p;
         }
         return newhead;
     }

 };
```
### [146.LRU Cache](http://oj.leetcode.com/problems/lru-cache/)
新建数据类class Val，保存key、val和访问自增标记updatecnt。

用unordered_map更新数据，增加updatecnt，并把更新的数据放入队列，最关键是处理capacity满了的时候，队列依次出队，map中不存在的和updatecnt和最新数据不相等的项目都忽略，直到发现updatecnt和map中存的最新状态相等，则为(最近未使用)数据，出队后在map中erase。思路有点像STL队列实现版本的Dijkstra。

[有一个博客](http://blog.csdn.net/doc_sgl/article/details/15378513) 的方法更好，map中存的是链表的节点指针，链表顺序表示访问情况，这样就把map内容和链表的每个节点一一对应了，没有冗余节点，且更新操作也是O(1)的。

```cpp
 class Val{
 public:
     int key;
     int val;
     int updatecnt;
 };
 class LRUCache{
 public:
     int cap;
     unordered_map<int, Val> mp;
     queue q;
     LRUCache(int capacity) {
         cap = capacity;
     }

     int get(int key) {
         if(mp.count(key))
         {
             mp[key].updatecnt ++;
             q.push(mp[key]);
             return mp[key].val;
         }
         return -1;
     }

     void set(int key, int value) {
         if(mp.count(key))
         {
             mp[key].val = value;
             mp[key].updatecnt ++;
             q.push(mp[key]);
         }
         else
         {
             if(mp.size() == cap)
             {
                 Val tmp;
                 while(!q.empty())
                 {
                     tmp = q.front();
                     q.pop();
                     if(mp.count(tmp.key) && tmp.updatecnt == mp[tmp.key].updatecnt)
                         break;
                 }
                 mp.erase(mp.find(tmp.key));
                 mp[key].key = key;
                 mp[key].val = value;
                 mp[key].updatecnt = 0;
                 q.push(mp[key]);
             }
             mp[key].key = key;
             mp[key].val = value;
             mp[key].updatecnt = 0;
             q.push(mp[key]);
         }
     }
 };
```
### [145.Binary Tree Postorder Traversal](http://oj.leetcode.com/problems/binary-tree-postorder-traversal/)
二叉树的非递归后序遍历，考研的时候非常熟悉了，现在写又要想好久。重点是关于右子树遍历时候需要一个标记，或者标记根节点出栈次数，或者标记右子树是否访问。

```cpp
 /**
  * Definition for binary tree
  * struct TreeNode {
  *     int val;
  *     TreeNode *left;
  *     TreeNode *right;
  *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
  * };
  */
 class Solution {
 public:
     vector postorderTraversal(TreeNode *root) {
         vector ans;
         if(root == NULL) return ans;
         stack<TreeNode*> s;
         TreeNode *visited;
         while(root != NULL || !s.empty())
         {
             while(root != NULL)
                 s.push(root), root = root->left;
             root = s.top();
             if(root->right == NULL || visited == root->right)
             {
                 ans.push_back(root->val);
                 s.pop();
                 visited = root;
                 root = NULL;
             }
             else
             {
                 root = root->right;
             }
         }
         return ans;
     }
 };
```
### [144.Binary Tree Preorder Traversal](http://oj.leetcode.com/problems/binary-tree-preorder-traversal/)
前序遍历的非递归就容易多了。

```cpp
 /**
  * Definition for binary tree
  * struct TreeNode {
  *     int val;
  *     TreeNode *left;
  *     TreeNode *right;
  *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
  * };
  */
 class Solution {
 public:
     vector preorderTraversal(TreeNode *root) {
         stack<TreeNode*> s;
         vector ans;
         if(root == NULL) return ans;
         s.push(root);
         while(!s.empty())
         {
             root = s.top();
             s.pop();
             ans.push_back(root->val);
             if(root->right != NULL) s.push(root->right);
             if(root->left != NULL) s.push(root->left);
         }
     }
 };
```
### [143.Reorder List](http://oj.leetcode.com/problems/reorder-list/)
找到中间位置，把中间之后的链表反转，两个指针一个从头一个从尾开始互插，奇偶和指针绕得有点晕，理清就好了。。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     void reorderList(ListNode *head) {
         int n = 0;
         ListNode *pre, *p = head;
         while(p)
             n ++, p = p->next;
         if(n < 3) return; n >>= 1;
         pre = p = head;
         p = p->next;
         while(n --) p = p->next, pre = pre->next;
         while(p != NULL)
         {
             ListNode *tmp = p->next;
             p->next = pre;
             pre = p;
             p = tmp;
         }
         ListNode *tail = pre;
         p = head;
         while(true)
         {
             ListNode *tmp1 = p->next, *tmp2 = tail->next;
             p->next = tail;
             tail->next = tmp1;
             p = tmp1;
             if(p == tail || p == tmp2) break;
             tail = tmp2;
         }
         p->next = NULL;
     }
 };
```
### [142.Linked List Cycle II](http://oj.leetcode.com/problems/linked-list-cycle-ii/)
设置两个指针`slow`和`fast`，从`head`开始，`slow`一次一步，`fast`一次两步，如果`fast`能再次追上`slow`则有圈。
设`slow`走了`n`步，则`fast`走了`2*n`步，设圈长度m，圈起点到`head`距离为`k`，相遇位置距离圈起点为`t`，则有：

`n = k + t + pm;` (1)

`2*n = k + t + qm;`(2)

这里p和q是任意整数。（不过fast速度是slow二倍，则肯定在一圈内追上，p就是0了）

`2 * (1) - (2)` 得`k = lm - t;(l = q - 2 * p)`

即 `k` 的长度是若干圈少了 `t` 的长度。
因此这时候，一个指针从`head`开始，另一个从相遇位置开始，都每次只走一步，当从`head`开始的指针走到圈开始位置时，两指针刚好相遇。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *detectCycle(ListNode *head) {
         if(head == NULL) return NULL;
         ListNode *slow, *fast;
         slow = fast = head;
         int n = 0;
         do
         {
             n ++;
             if(slow == NULL || fast == NULL) return NULL;
             slow = slow->next;
             fast = fast->next;
             if(fast == NULL) return NULL;
             fast = fast->next;
             if(fast == NULL) return NULL;
         }while(slow != fast);
         fast = head;
         while(slow != fast)
             slow = slow->next, fast = fast->next;
         return fast;
     }
 };
```
### [141.Linked List Cycle](http://www.cnblogs.com/CSGrandeur/admin/Linked%20List%20Cycle%20)
