### [140.Word Break II](http://oj.leetcode.com/problems/word-break-ii/)
先递推，`dp[i] == true` 表示 `s` 中前 `i` 个字符的串是符合要求的，枚举位置 `i` ，对于 `i` 枚举位置 `j < i`，如果 `dp[j] == true`且 `j ~ i`的串在字典中，则`dp[i] = true`。

同时对于这样的 `j`, `i`，`site[i].push_back(j)`，即在 `i` 位置的可行迭代表中增加位置 `j`。

完成site之后，从尾部倒着DFS过去就得到了所有串。

```cpp
 class Solution {
 public:
     vector DFS(const string &s, vector *site, int ith)
     {
         vector res;
         for(int i = 0; i < site[ith].size(); i ++)
         {
             vector tmp;
             string str = s.substr(site[ith][i], ith - site[ith][i]);
             if(site[site[ith][i]].size() == 0)
                 res.push_back(str);
             else
             {
                 tmp = DFS(s, site, site[ith][i]);
                 for(int j = 0; j < tmp.size(); j ++)
                     res.push_back(tmp[j] + " " + str);
             }
         }
         return res;
     }
     vector wordBreak(string s, unordered_set &dict) {
         vector *site = new vector[s.length() + 1];
         bool *dp = new bool[s.length() + 1];
         memset(dp, 0, sizeof(bool) * s.length());
         dp[0] = true;
         for(int i = 1; i <= s.length(); i ++)
         {
             for(int j = 0; j < i; j ++)
             {
                 if(dp[j] == true && dict.count(s.substr(j, i - j)))
                    site[i].push_back(j), dp[i] = true;
             }
         }
         return DFS(s, site, s.length());
     }
 };
```
### [139.Word Break](http://oj.leetcode.com/problems/word-break/)
参考Word Break II，对于dp标记，当dp[i]为true时候可以停止枚举后面的 j，优化一下常数。

```cpp
 class Solution {
 public:
     bool wordBreak(string s, unordered_set &dict) {
         bool *dp = new bool[s.length() + 1];
         memset(dp, 0, sizeof(bool) * (s.length() + 1));
         dp[0] = true;
         for(int i = 1; i <= s.length(); i ++)
             for(int j = 0; j < i; j ++)
             {
                 dp[i] = dp[i] || dp[j] && dict.count(s.substr(j, i - j));
             }
         return dp[s.length()];
     }
 };
```
### [138.Copy List with Random Pointer](http://oj.leetcode.com/problems/copy-list-with-random-pointer/)
第一次遍历，把每个节点复制一份放到对应节点的下一个，即组成二倍长的链表：`ori1->copy1->ori2->copy2->...`

第二次遍历，利用`复制节点总是对应节点的下一个节点`特性，将每个`ori->next->random`指向`ori->random->next`，中间判断一下空指针。

第三次遍历，把两个链表拆开，恢复原链表。

```cpp
 /**
  * Definition for singly-linked list with a random pointer.
  * struct RandomListNode {
  *     int label;
  *     RandomListNode *next, *random;
  *     RandomListNode(int x) : label(x), next(NULL), random(NULL) {}
  * };
  */
 class Solution {
 public:
     RandomListNode *copyRandomList(RandomListNode *head) {
         RandomListNode *p = head, *newhead = NULL, *tmp;
         if(p == NULL) return NULL;
         while(p != NULL)
         {
             tmp = new RandomListNode(p->label);
             tmp->next = p->next;
             p->next = tmp;
             p = tmp->next;
         }
         newhead = head->next;
         p = head;
         while(p != NULL)
         {
             tmp = p->next;
             tmp->random = p->random == NULL ? NULL : p->random->next;
             p = tmp->next;
         }
         p = head;
         while(p != NULL)
         {
             tmp = p->next;
             p->next = tmp->next;
             p = tmp->next;
             tmp->next = p == NULL ? NULL : p->next;
         }
         return newhead;
     }
 };
```
### [137.Single Number II](http://oj.leetcode.com/problems/single-number-ii/)
方法一：设置cnt[32]记录 32个比特位的1的个数，出现3次的数的对应位的1总数为3的倍数，则统计之后每个位对3取模，剩下的位为1的则对应个数为1的那个数。

```cpp
 class Solution {
 public:
     int singleNumber(int A[], int n) {
         int cnt[32] = {0};
         for(int i = 0; i < n; i ++)
         {
             int tmp = A[i];
             for(int j = 0; j < 33; tmp >>= 1, j ++)
                 cnt[j] += tmp & 1;
         }
         int ans = 0;
         for(int i = 0; i < 32; i ++)
             ans |= (cnt[i] % 3) << i;
         return ans;
     }
 };
```
方法二：设置int one, two模拟两位二进制来统计各比特位1次数，每当one和two对应二进制位都为1的时候把one和two都清零，最后剩下的one就是要求的数。

```cpp
 class Solution {
 public:
     int singleNumber(int A[], int n) {
         int one = 0, two = 0;
         for(int i = 0; i < n; i ++)
         {
             two |= one & A[i];
             one ^= A[i];
             int tmp = one & two;
             two ^= tmp;
             one ^= tmp;
         }
         return one;
     }
 };
```
