```cpp
 class Solution {
 public:
     bool valid(char &x)
     {
         x = tolower(x);
         return isdigit(x) || isalpha(x);
     }
     bool isPalindrome(string s) {
         if(s.length() == 0) return true;
         for(int i = 0, j = s.length() - 1; i < j; i ++, j --)
         {
             while(!valid(s[i]) && i < s.length()) i ++; while(!valid(s[j]) && j >= 0) j --;
             if(i < j && s[i] != s[j]) return false;
         }
         return true;
     }
 };
