### [109.Convert Sorted List to Binary Search Tree](http://oj.leetcode.com/problems/convert-sorted-list-to-binary-search-tree/)
每次找中点作为根节点，将两边递归，返回根节点指针作为左右节点。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 /**
  * Definition for binary tree
  * struct TreeNode {
  *     int val;
  *     TreeNode *left;
  *     TreeNode *right;
  *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
  * };
  */
 class Solution {
 public:
     TreeNode *sortedListToBST(ListNode *head) {
         if(head == NULL) return NULL;
         ListNode *p, *mid, *pre;
         for(p = mid = head, pre = NULL; p->next != NULL; mid = mid->next)
         {
             p = p->next;
             if(p->next == NULL) break;
             p = p->next;
             pre = mid;
         };
         TreeNode *root = new TreeNode(mid->val);
         if(pre != NULL) pre->next = NULL, root->left = sortedListToBST(head);
         else root->left = NULL;
         root->right = sortedListToBST(mid->next);
         if(pre != NULL) pre->next = mid;
         return root;
     }
 };
```
