### [92.Reverse Linked List II](http://oj.leetcode.com/problems/reverse-linked-list-ii/)
在表头添加一个(哨兵)会好写很多，额外的newhead可以帮助标记翻转之后更换了的头指针。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *reverseBetween(ListNode *head, int m, int n) {
         ListNode *newhead = new ListNode(0);
         newhead->next = head;
         ListNode *pre = newhead, *p = head, *start = NULL;
         ListNode *tmp;
         for(int i = 1; p != NULL; i ++)
         {
             tmp = p->next;
             if(i == m)
                 start = pre;
             if(i > m && i <= n) p->next = pre;
             if(i == n)
             {
                 start->next->next = tmp;
                 start->next = p;
             }
             pre = p;
             p = tmp;
         }
         tmp = newhead->next;
         free(newhead);
         return tmp;
     }
 };
