 class Solution {
 public:
     void merge(int A[], int m, int B[], int n) {
         int p = m + n - 1, i = m - 1, j = n - 1;
         for(; i >= 0 && j >= 0;)
         {
             if(A[i] > B[j]) A[p --] = A[i --];
             else A[p --] = B[j --];
         }
         while(i >= 0) A[p --] = A[i --];
         while(j >= 0) A[p --] = B[j --];
     }
