### [85.Maximal Rectangle](http://oj.leetcode.com/problems/maximal-rectangle/)
方法一：`linecnt[i][j]`统计第 `i` 行到第 `j` 位置有多少个连续的 `'1'`，接下来枚举列，每一列相当于一次直方图最大矩形统计，计算每个位置向前和向后最远的不少于当前位置值的位置，每次更新结果，总复杂度`O(n^2)`。

找(最远位置)用迭代指针，理论复杂度略高于`O(n)`。

```cpp
 class Solution {
 public:
     int maximalRectangle(vector &matrix) {
         if(matrix.size() == 0) return 0;
         int H = matrix.size(), W = matrix[0].size();
         int ans = 0;
         vector left(H), right(H);
         vector linecnt(H, vector(W, 0));
         for(int i = 0; i < H; i ++)
         {
             int last = 0;
             for(int j = 0; j < W; j ++)
             {
                 if(matrix[i][j] == '1') last ++;
                 else last = 0;
                 linecnt[i][j] = last;
             }
         }
         for(int k = 0; k < W; k ++)
         {
             for(int i = 0; i < H; i ++) 
             { 
                if(i == 0) left[i] = -1; 
                else 
                { 
                    left[i] = i - 1; 
                    while(left[i] > -1 && linecnt[left[i]][k] >= linecnt[i][k])
                         left[i] = left[left[i]];
                }
             }
             for(int i = H - 1; i >= 0; i --)
             {
                 if(i == H - 1) right[i] = H;
                 else
                 {
                     right[i] = i + 1;
                     while(right[i] < H && linecnt[right[i]][k] >= linecnt[i][k])
                         right[i] = right[right[i]];
                 }
                 ans = max(ans, (right[i] - left[i] - 1) * linecnt[i][k]);
             }
         }
         return ans;
     }
 };
```
用单调栈，理论复杂度O(n)。

```cpp
 class Solution {
 public:
     int maximalRectangle(vector &matrix) {
         if(matrix.size() == 0) return 0;
         vector linecnt(matrix.size(), vector(matrix[0].size(), 0));
         for(int i = 0; i < matrix.size(); i ++)
         {
             int last = 0;
             for(int j = 0; j < matrix[0].size(); j ++)
             {
                 if(matrix[i][j] == '1') last ++;
                 else last = 0;
                 linecnt[i][j] = last;
             }
         }
         int ans = 0;
         for(int k = 0; k < matrix[0].size(); k ++)
         {
             stack s, site;
             vectorlast(matrix.size());
             for(int i = 0; i < matrix.size(); i ++) { while(!s.empty() && s.top() >= linecnt[i][k])
                     s.pop(), site.pop();
                 if(!s.empty()) last[i] = site.top() + 1;
                 else last[i] = 0;
                 s.push(linecnt[i][k]);
                 site.push(i);
             }
             while(!s.empty()) s.pop(), site.pop();
             for(int i = matrix.size() - 1; i >= 0; i --)
             {
                 while(!s.empty() && s.top() >= linecnt[i][k])
                     s.pop(), site.pop();
                 if(!s.empty()) ans = max(ans, (site.top() - last[i]) * linecnt[i][k]);
                 else ans = max(ans, (int)(matrix.size() - last[i]) * linecnt[i][k]);
                 s.push(linecnt[i][k]);
                 site.push(i);
             }
         }
         return ans;
     }
 };
```
方法二：每个 `1` 的点当作一个矩形的底部，`left[j]、right[j]、height[j]`表示当前行第 `j`个位置这个点向左、右、上伸展的最大矩形的边界，作为滚动数组，下一行的数据可以由上一行结果得到，总复杂度O(n^2)。

`left[j] = max(这一行最左, left[j]（上一行最左） );`

`right[j] = min(这一行最右，right[j]（上一行最右） );`

`height[j] = height[j - 1] + 1;`


```cpp
 class Solution {
 public:
     int maximalRectangle(vector &matrix) {
         if(matrix.size() == 0) return 0;
         int H = matrix.size(), W = matrix[0].size();
         vector left(W, -1), right(W, W), height(W, 0);
         int ans = 0;
         for(int i = 0; i < H; i ++)
         {
             int last = -1;
             for(int j = 0; j < W; j ++) 
             { 
                if(matrix[i][j] == '1') 
                { 
                    if(last == -1) last = j; 
                    left[j] = max(left[j], last); 
                    height[j] ++;
                } 
                else 
                { 
                    last = -1; left[j] = -1; height[j] = 0; 
                } 
              } last = -1; 
              for(int j = W - 1; j >= 0; j --)
              {
                 if(matrix[i][j] == '1')
                 {
                     if(last == -1) last = j;
                     right[j] = min(right[j], last);
                     ans = max(ans, height[j] * (right[j] - left[j] + 1));
                 }
                 else
                 {
                     last = -1;
                     right[j] = W;
                 }
             }
         }
         return ans;
     }
 };
```
### [84.Largest Rectangle in Histogram](http://oj.leetcode.com/problems/largest-rectangle-in-histogram/)
