### [83.Remove Duplicates from Sorted List II](http://oj.leetcode.com/problems/remove-duplicates-from-sorted-list-ii/)
加个表头乱搞吧。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *deleteDuplicates(ListNode *head) {
         if(head == NULL || head->next == NULL) return head;
         ListNode *newhead = new ListNode(0);
         newhead->next = head;
         for(ListNode *pre = newhead, *now = head, *nex = head->next; nex != NULL;)
         {
             if(now->val == nex->val)
             {
                 while(nex != NULL && now->val == nex->val)
                 {
                     free(now);
                     now = nex;
                     nex = nex->next;
                 }
                 free(now);
                 pre->next = nex;
                 if(nex == NULL) break;
             }
             else pre = now;
             now = nex;
             nex = nex->next;
         }
         head = newhead->next;
         free(newhead);
         return head;
     }
 };
