### [79.Word Search](http://oj.leetcode.com/problems/word-search/)
基础DFS。

```cpp
 class Solution {
 public:
     int dx[4] = {1, -1, 0, 0};
     int dy[4] = {0, 0, 1, -1};
     bool DFS(int x, int y, vector &board, string word, int ith)
     {
         if(board[x][y] != word[ith]) return false;
         if(ith == word.length() - 1) return true;
         board[x][y] = '.';
         for(int i = 0; i < 4; i ++) 
         { 
            int nx = x + dx[i]; int ny = y + dy[i]; 
            if(nx >= 0 && ny >= 0 && nx < board.size() && ny < board[0].size())
             {
                 if(DFS(nx, ny, board, word, ith + 1))
                 {
                     board[x][y] = word[ith];
                     return true;
                 }
             }
         }
         board[x][y] = word[ith];
         return false;
     }
     bool exist(vector &board, string word) {
         for(int i = 0; i < board.size(); i ++)
         {
             for(int j = 0; j < board[0].size(); j ++)
             {
                 if(DFS(i, j, board, word, 0)) return true;
             }
         }
         return false;
     }
 };
