```cpp
 class Solution {
 public:
     vector now;
     vector res;
     void DFS(int n, int ith, int sum, int k)
     {
         if(sum == k)
         {
             res.push_back(now);
             return;
         }
         if(sum + n - ith + 1 > k)
         {
             DFS(n, ith + 1, sum, k);
         }
         now.push_back(ith);
         DFS(n, ith + 1, sum + 1, k);
         now.pop_back();
     }
     vector combine(int n, int k) {
         DFS(n, 1, 0, k);
         return res;
     }
 };
