 class Solution {
 public:
     void sortColors(int A[], int n) {
         int find = 0;
         for(int i = 0, j = n - 1; i < n; i ++) { if(A[i] == find) continue; while(j > i && A[j] != find) j --;
             if(j > i) swap(A[i], A[j]);
             else i --, j = n - 1, find ++;
         }
     }
 };
