找到哪个放哪个：

```cpp
 class Solution {
 public:
     void sortColors(int A[], int n) {
         int p0, p1, p2;
         for(p0 = 0, p1 = p2 = n - 1; p0 < p1; )
         {
             if(A[p0] == 0) p0 ++;
             if(A[p0] == 1) swap(A[p0], A[p1 --]);
             if(A[p0] == 2)
             {
                 swap(A[p0], A[p2 --]);
                 p1 = p2;
             }
         }
     }
 };
