 class Solution {
 public:
     vector plusOne(vector &digits) {
         int cur, i;
         if(digits.size() == 0) return digits;
         for(i = digits.size() - 1, cur = 1; i >= 0; i --)
         {
             int tmp = digits[i] + cur;
             cur = tmp / 10;
             digits[i] = tmp % 10;
         }
         if(cur) digits.insert(digits.begin(), cur);
         return digits;
     }
 };
