     int minPathSum(vector &grid) {
         if(grid.size() == 0) return 0;
         for(int i = 0; i < grid.size(); i ++)
         {
             for(int j = 0; j < grid[0].size(); j ++) { int tmp = 0x3f3f3f3f; if(i > 0) tmp = min(tmp, grid[i][j] + grid[i - 1][j]);
