这是当年学组合数时候的经典题型吧。

```cpp
 class Solution {
 public:
     int COM(int a, int b)
     {
         b = min(b, a - b);
         int ret = 1, i, j;
         for(i = a, j = 1; i > a - b; i --)
         {
             ret *= i;
             for(; j <= b && ret % j == 0; j ++)
                 ret /= j;
         }
         return ret;
     }
     int uniquePaths(int m, int n) {
         return COM(m + n - 2, m - 1);
     }
 };
