### [61.Rotate List](http://oj.leetcode.com/problems/rotate-list/)
因为k可能比长度大，需要求长度然后k对长度取模。那么就不要矫情地追求双指针一遍扫描了。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *rotateRight(ListNode *head, int k) {
         if(head == NULL) return NULL;
         int cnt;
         ListNode *en, *p;
         for(cnt = 1, en = head; en->next != NULL; cnt ++, en = en->next);
         k %= cnt;
         for(p = head, cnt --; cnt != k; cnt --, p = p->next);
         en->next = head;
         en = p->next;
         p->next = NULL;
         return en;
     }
 };
```
### [60.Permutation Sequence](http://oj.leetcode.com/problems/permutation-sequence/)
一位一位算，每一位优先没使用过的较小的数字，而其后剩下的m个位置有 m! 种排列方法，用 k 减去，直到k不大于这个方法数，则这一位就是枚举到的这个数。

```cpp
 class Solution {
 public:
     int permu[10];
     bool vis[10];
     string getPermutation(int n, int k) {
         permu[0] = 1;
         for(int i = 1; i < 10; i ++) permu[i] = permu[i - 1] * i;
         memset(vis, 0, sizeof(vis));
         string ans;
         for(int i = 1; i <= n; i ++)
         {
             for(int j = 1; j <= n; j ++) { if(!vis[j]) { if(k > permu[n - i])
                         k -= permu[n - i];
                     else 
                     {
                         ans += '0' + j;
                         vis[j] = true;
                         break;
                     }
                 }
             }
         }
         return ans;
     }
 };
