### [54.Spiral Matrix](http://oj.leetcode.com/problems/spiral-matrix/)
模拟转一遍吧。写了俩代码，差不多，处理拐弯的方式略有不同。

代码一：

```cpp
 class Solution {
 public:
     int dx[4] = {0, 1, 0, -1};
     int dy[4] = {1, 0, -1, 0};
     vector res;
     bool JudgeValid(int x, int y,
         vector &vis, vector &matrix)
     {
         return x >= 0 && x < matrix.size() && y >= 0 && y < matrix[0].size() && 
            vis[x][y] == false;
     }
     vector spiralOrder(vector &matrix) {
         int dir, x, y, nx, ny;
         if(matrix.size() == 0) return res;

         vector vis(matrix.size(), vector(matrix[0].size(), false));
         for(dir = x = y = 0; JudgeValid(x, y, vis, matrix); x = nx, y = ny)
         {
             res.push_back(matrix[x][y]);
             vis[x][y] = true;
             nx = x + dx[dir];
             ny = y + dy[dir];
             if(!JudgeValid(nx, ny, vis, matrix))
             {
                 dir = (dir + 1) % 4;
                 nx = x + dx[dir];
                 ny = y + dy[dir];
             }
         }
         return res;
     }
 };
```
代码二：

```cpp
 class Solution {
 public:
     int dx[4] = {0, 1, 0, -1};
     int dy[4] = {1, 0, -1, 0};
     vector res;
     vector spiralOrder(vector &matrix) {
         int dir, x, y, nx, ny;
         int l, r, u, d;
         if(matrix.size() == 0) return res;

         l = u = -1;
         r = matrix[0].size();
         d = matrix.size();
         for(dir = x = y = 0; res.size() < matrix.size() * matrix[0].size();
             x = nx, y = ny)
         {
             res.push_back(matrix[x][y]);
             nx = x + dx[dir];
             ny = y + dy[dir];
             if(nx == d || nx == u || ny == r || ny == l)
             {
                 dir = (dir + 1) % 4;
                 if(dir == 0) l ++, r --, d --;
                 else if(dir == 3) u ++;
                 nx = x + dx[dir];
                 ny = y + dy[dir];
             }
         }
         return res;
     }
 };
