### [47.Permutations II](http://oj.leetcode.com/problems/permutations-ii/)
有重复数字，把数字统计起来好了。因为题目没说数字大小，所以统计用了unordered_map。

也可以把数组排序，DFS时跳过重复的数字。

```cpp
 class Solution {
 public:
     unordered_map<int, int> mp;
     vector tmp;
     vector res;
     int numsize;
     void DFS(int cnt)
     {
         if(cnt == numsize)
         {
             res.push_back(tmp);
         }
         for(unordered_map<int, int>::iterator it = mp.begin(); it != mp.end(); it ++)
         {
             if(it->second != 0)
             {
                 tmp.push_back(it->first);
                 it->second --;
                 DFS(cnt + 1);
                 tmp.pop_back();
                 it->second ++;
             }
         }
     }
     vector permute(vector &num) {
         numsize = num.size();
         for(int i = 0; i < num.size(); i ++)
         {
             if(!mp.count(num[i])) mp[num[i]] = 1;
             else mp[num[i]] ++;
         }
         DFS(0);
         return res;
     }
 };
```
