 class Solution {
 public:
     string countAndSay(int n) {
         string f[2];
         f[0] = "1";
         for(int i = 1; i < n; i ++)
         {
             f[i & 1].clear();
             for(int j = 0; j < f[i & 1 ^ 1].length();)
             {
                 int cnt;
                 char x = f[i & 1 ^ 1][j];
                 for(cnt = 0; j < f[i & 1 ^ 1].length() && f[i & 1 ^ 1][j] == x; cnt ++, j ++);
