### [37.Sudoku Solver](http://oj.leetcode.com/problems/sudoku-solver/)
这道题考察回溯和数独结果的判断。ACM做过，就直接拿dancing links代码了，4ms。

关于dancing links，对于面试题来说变态了些，应该不至于考察。

```cpp
 class Solution {
 public:
     int rw[10], cl[10], in[10], RW[81], CL[81], IN[81], goal;
     char buf[100];
     void Mark(int i, int num)
     {
         rw[RW[i]] ^= 1 << num;
         cl[CL[i]] ^= 1 << num;
         in[IN[i]] ^= 1 << num;
     }
     void init()
     {
         int i;
         for(i = 0; i < 10; ++ i)
             cl[i] = rw[i] = in[i] = 0;
         for(i = goal = 0; buf[i]; ++ i)
             goal += buf[i] == '.';
         for(i = 0; i < 81; ++ i)
         {
             RW[i] = i / 9, CL[i] = i % 9, IN[i] = i / 3 % 3 + i / 27 * 3;
             if(buf[i] != '.')
                 Mark(i, buf[i] - '1');
         }
     }
     inline int Judge(int i, int num)
     {return ~(rw[RW[i]] | cl[CL[i]] | in[IN[i]]) & (1 << num);}
     int Oper(int sx, int k, int cur)
     {
         Mark(sx, k), buf[sx] = k + '1';
         if(dfs(cur + 1)) return 1;
         Mark(sx, k), buf[sx] = '.';
         return 0;
     }
     int JudgeRWCLIN(int cur)
     {
         int i, j, k, x, cnt, sx;
         for(i = 0; i < 9; ++ i)
             for(k = 0; k < 9; ++ k)
             {
                 if(~rw[i] & (1 << k))
                 {
                     for(j = cnt = 0; j < 9; ++ j)
                     {
                         x = i * 9 + j;
                         if(buf[x] == '.' && Judge(x, k)) ++ cnt, sx = x;
                     }
                     if(cnt == 0) return 0;
                     else if(cnt == 1)
                         return Oper(sx, k, cur);
                 }
                 if(~cl[i] & (1 << k))
                 {
                     for(j = cnt = 0; j < 9; ++ j)
                     {
                         x = j * 9 + i;
                         if(buf[x] == '.' && Judge(x, k)) ++ cnt, sx = x;
                     }
                     if(cnt == 0) return 0;
                     else if(cnt == 1)
                         return Oper(sx, k, cur);
                 }
                 if(~in[i] & (1 << k))
                 {
                     for(j = cnt = 0; j < 9; ++ j)
                     {
                         x = i / 3 * 27 + j / 3 * 9 + i % 3 * 3 + j % 3;
                         if(buf[x] == '.' && Judge(x, k)) ++ cnt, sx = x;
                     }
                     if(cnt == 0) return 0;
                     else if(cnt == 1)
                         return Oper(sx, k, cur);
                 }
             }
         return 2;
     }

     bool dfs(int cur)
     {
         int i, j, num, cnt;
         if(cur == goal) return true;
         for(i = 0; i < 81; ++ i)
             if(buf[i] == '.')
             {
                 for(j = cnt = 0; j < 9; ++ j)
                     if(Judge(i, j)) ++ cnt, num = j;
                 if(cnt == 0) return false;
                 if(cnt == 1)
                         return Oper(i, num, cur);
             }
         if((num = JudgeRWCLIN(cur)) == 0) return false;
         else if(num == 1) return true;
         for(i = 0; i < 81; ++ i)
             if(buf[i] == '.')
             {
                 for(j = 0; j < 9; ++ j)
                     if(Judge(i, j))
                     {
                         Mark(i, j), buf[i] = j + '1';
                         if(dfs(cur + 1)) return true;
                         Mark(i, j), buf[i] = '.';
                     }
             }
         return false;
     }
     void solveSudoku(vector &board) {
         int site = 0;
         for(int i = 0; i < 9; i ++)
             for(int j = 0; j < 9; j ++)
                 buf[site ++] = board[i][j];
         init();
         dfs(0);
         site = 0;
         for(int i = 0; i < 9; i ++)
             for(int j = 0; j < 9; j ++)
                 board[i][j] = buf[site ++];
     }
 };
```
### [36.Valid Sudoku](http://oj.leetcode.com/problems/valid-sudoku/)
