```cpp
 class Solution {
 public:
     bool isValidSudoku(vector &board) {
         bool flag[3][9][9];
         memset(flag, false, sizeof(flag));
         for(int i = 0; i < 9; i ++)
         {
             for(int j = 0; j < 9; j ++)
             {
                 if(board[i][j] != '.')
                 {
                     int x = board[i][j] - '1';
                     if(flag[0][i][x] == true) return false;
                     flag[0][i][x] = true;
                     if(flag[1][j][x] == true) return false;
                     flag[1][j][x] = true;
                     if(flag[2][i / 3 * 3 + j / 3][x] == true) return false;
                     flag[2][i / 3 * 3 + j / 3][x] = true;
                 }
             }
         }
         return true;
     }
 };
