### [25.Reverse Nodes in k-Group](http://oj.leetcode.com/problems/reverse-nodes-in-k-group/)
用头插法来做的，顺序插入到首节点之后，就反转了。每 k 个节点处理之后，把首节指针点移动到下 k 个的开头。最后面不足 k 个的话，再反转回来。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     int Reverse(ListNode *&pre, ListNode *&p, int k)
     {
         int i;
         ListNode *nex, *tmp;
         for(i = 1; p != NULL; i ++, p = tmp)
         {
             if(i == 1) nex = p;
             tmp = p->next;
             p->next = pre->next;
             pre->next = p;
             if(i == k) i = 0, pre = nex;
         }
         nex->next = NULL;
         return i;
     }
     ListNode *reverseKGroup(ListNode *head, int k) {
         if(head == NULL) return NULL;
         ListNode *tmphead = new ListNode(0), *pre = tmphead, *p = head;
         tmphead->next = head;
         if(Reverse(pre, p, k) != 1)
         {
             p = pre->next;
             Reverse(pre, p, k);
         }
         return tmphead->next;
     }
 };
```
### [24.Swap Nodes in Pairs](http://oj.leetcode.com/problems/swap-nodes-in-pairs/)
Reverse Nodes in k-Group的简化版。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *swapPairs(ListNode *head) {
         if(head == NULL) return NULL;
         ListNode *tmphead = new ListNode(0), *pre = tmphead, *p = head, *tmp, *nex;
         tmphead->next = head;
         for(int i = 0; p != NULL; i ++, p = tmp)
         {
             if(i & 1 ^ 1) nex = p;
             tmp = p->next;
             p->next = pre->next;
             pre->next = p;
             if(i & 1) pre = nex;
         }
         nex->next = NULL;
         return tmphead->next;
     }
 };
