### [23.Merge k Sorted Lists](http://oj.leetcode.com/problems/merge-k-sorted-lists/)
一个堆（这里用了优先级队列），把所有 list 的首元素放堆里，O(logn)取得最小值插入新队列，异步推进。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     struct comp
     {
         bool operator()(ListNode *a,ListNode *b)
         {return a->val > b->val;}
     };
     ListNode *mergeKLists(vector &lists) {
         ListNode *tmphead = new ListNode(0), *p = tmphead;
         priority_queue<ListNode*, vector<ListNode*>, comp> q;
         for(int i = 0; i < lists.size(); i ++) if(lists[i] != NULL) q.push(lists[i]); while(!q.empty()) { p->next = q.top();
             p = p->next;
             q.pop();
             if(p ->next != NULL) q.push(p->next);
         }
         return tmphead->next;
     }
 };
```
### [22.Generate Parentheses](http://oj.leetcode.com/problems/generate-parentheses/)
DFS，保持当前右括号不多于左括号。

```cpp
 class Solution {
 public:
     string tmp;
     vector ans;
     void DFS(int left, int right, int n)
     {
         if(left == right && left == n)
         {
             ans.push_back(tmp);
             return;
         }
         if(left < n)
         {
             tmp[left + right] = '(';
             DFS(left + 1, right, n);
         }
         if(right < left)
         {
             tmp[left + right] = ')';
             DFS(left, right + 1, n);
         }
     }
     vector generateParenthesis(int n) {
         tmp.resize(n << 1);
         DFS(0, 0, n);
         return ans;
     }
 };
