### [20.Valid Parentheses](http://oj.leetcode.com/problems/valid-parentheses/)
用栈配对。

```cpp
 class Solution {
 public:
     bool isValid(string s) {
         stack st;
         for(int i = 0; i < s.length(); i ++)
         {
             switch(s[i])
             {
                 case '(': st.push('('); break;
                 case '[': st.push('['); break;
                 case '{': st.push('{'); break;
                 case ')':
                     if(st.empty() || st.top() != '(') return false;
                     st.pop(); break;
                 case ']':
                     if(st.empty() || st.top() != '[') return false;
                     st.pop(); break;
                 case '}':
                     if(st.empty() || st.top() != '{') return false;
                     st.pop(); break;

             }
         }
         return st.empty();
     }
 };
