### [19.Remove Nth Node From End of List](http://oj.leetcode.com/problems/remove-nth-node-from-end-of-list/)
两个指针相隔 n 距离，前面的指针到了末尾，后面的指针就是删除的位置。

```cpp
 /**
  * Definition for singly-linked list.
  * struct ListNode {
  *     int val;
  *     ListNode *next;
  *     ListNode(int x) : val(x), next(NULL) {}
  * };
  */
 class Solution {
 public:
     ListNode *removeNthFromEnd(ListNode *head, int n) {
         ListNode *pre, *slow, *quick;
         ListNode *newhead = new ListNode(0);
         newhead->next = head;
         int i = 0;
         for(pre = slow = quick = newhead; quick != NULL; i ++)
         {
             pre = slow;
             if(i >= n) slow = slow->next;
             quick = quick->next;
         }
         pre->next = slow->next;
         free(slow);
         return newhead->next;
     }
 };
