```cpp
class Solution {  
public:  
    int ro[128];
    int romanToInt(string s) {
        ro['I'] = 1;
        ro['V'] = 5;
        ro['X'] = 10;
        ro['L'] = 50;
        ro['C'] = 100;
        ro['D'] = 500;
        ro['M'] = 1000;
        int ans = -1, last;
        for(int i = s.length() - 1; i >= 0; i --)
        {
            if(ans == -1) ans = ro[s[i]];
            else
            {
                if(last > ro[s[i]]) ans -= ro[s[i]];
                else ans += ro[s[i]];
            }
            last = ro[s[i]];
        }
        return ans;
    }
};
